INSERT INTO contract_templates (name, category, description, template_content, variables) VALUES 
('Договор факторинга', 'financial', 'Договор финансирования под уступку денежного требования', '<div style="text-align: center; font-weight: bold; font-size: 16pt; margin-bottom: 30px;">ДОГОВОР ФАКТОРИНГА № {{contract_number}}</div><div style="text-align: right; margin-bottom: 20px;">г. {{city}}, {{contract_date}}</div><p style="text-align: justify; line-height: 1.6;">{{factor_name}}, именуемый в дальнейшем "Фактор", с одной стороны, и {{client_name}}, именуемый в дальнейшем "Клиент", с другой стороны, заключили настоящий договор о нижеследующем:</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">1. ПРЕДМЕТ ДОГОВОРА</div><p style="text-align: justify;">1.1. Клиент уступает Фактору денежное требование к {{debtor_name}} в размере {{claim_amount}} рублей.</p><p style="text-align: justify;">1.2. Фактор выплачивает Клиенту финансирование в размере {{financing_amount}} рублей.</p><table width="100%" style="margin-top: 30px;"><tr valign="top"><td width="50%" style="text-align: center;"><strong>Фактор:</strong><br/>{{factor_name}}<br/>Лицензия: {{factor_license}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{factor_signature}}/</td><td width="50%" style="text-align: center;"><strong>Клиент:</strong><br/>{{client_name}}<br/>ИНН: {{client_inn}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{client_signature}}/</td></tr></table>', JSON_OBJECT('contract_number', 'Номер договора', 'city', 'Город заключения', 'contract_date', 'Дата заключения', 'factor_name', 'Наименование фактора', 'client_name', 'Наименование клиента', 'debtor_name', 'Наименование должника', 'claim_amount', 'Сумма требования', 'financing_amount', 'Сумма финансирования', 'factor_license', 'Лицензия фактора', 'client_inn', 'ИНН клиента', 'factor_signature', 'Подпись фактора', 'client_signature', 'Подпись клиента')),

-- КОММЕРЧЕСКИЕ ДОГОВОРЫ
('Договор коммерческой концессии', 'commercial', 'Договор франчайзинга на использование комплекса исключительных прав', '<div style="text-align: center; font-weight: bold; font-size: 16pt; margin-bottom: 30px;">ДОГОВОР КОММЕРЧЕСКОЙ КОНЦЕССИИ № {{contract_number}}</div><div style="text-align: right; margin-bottom: 20px;">г. {{city}}, {{contract_date}}</div><p style="text-align: justify; line-height: 1.6;">{{right_holder_name}}, именуемый(-ая) в дальнейшем "Правообладатель", с одной стороны, и {{user_name}}, именуемый(-ая) в дальнейшем "Пользователь", с другой стороны, заключили настоящий договор о нижеследующем:</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">1. ПРЕДМЕТ ДОГОВОРА</div><p style="text-align: justify;">1.1. Правообладатель предоставляет Пользователю за вознаграждение право использовать в предпринимательской деятельности комплекс исключительных прав: {{rights_complex}}.</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">2. ТЕРРИТОРИЯ ИСПОЛЬЗОВАНИЯ</div><p style="text-align: justify;">2.1. Территория использования: {{usage_territory}}.</p><table width="100%" style="margin-top: 30px;"><tr valign="top"><td width="50%" style="text-align: center;"><strong>Правообладатель:</strong><br/>{{right_holder_name}}<br/>Адрес: {{right_holder_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{right_holder_signature}}/</td><td width="50%" style="text-align: center;"><strong>Пользователь:</strong><br/>{{user_name}}<br/>Адрес: {{user_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{user_signature}}/</td></tr></table>', JSON_OBJECT('contract_number', 'Номер договора', 'city', 'Город заключения', 'contract_date', 'Дата заключения', 'right_holder_name', 'Наименование правообладателя', 'user_name', 'Наименование пользователя', 'rights_complex', 'Комплекс исключительных прав', 'usage_territory', 'Территория использования', 'right_holder_address', 'Адрес правообладателя', 'user_address', 'Адрес пользователя', 'right_holder_signature', 'Подпись правообладателя', 'user_signature', 'Подпись пользователя')),

-- НЕДВИЖИМОСТЬ
('Договор долевого участия в строительстве', 'real_estate', 'Договор участия в долевом строительстве', '<div style="text-align: center; font-weight: bold; font-size: 16pt; margin-bottom: 30px;">ДОГОВОР УЧАСТИЯ В ДОЛЕВОМ СТРОИТЕЛЬСТВЕ № {{contract_number}}</div><div style="text-align: right; margin-bottom: 20px;">г. {{city}}, {{contract_date}}</div><p style="text-align: justify; line-height: 1.6;">{{developer_name}}, именуемый в дальнейшем "Застройщик", с одной стороны, и {{participant_name}}, именуемый(-ая) в дальнейшем "Участник долевого строительства", с другой стороны, заключили настоящий договор о нижеследующем:</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">1. ПРЕДМЕТ ДОГОВОРА</div><p style="text-align: justify;">1.1. Застройщик обязуется в предусмотренный договором срок построить многоквартирный дом и передать Участнику долевого строительства объект долевого строительства: {{construction_object}}.</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">2. ЦЕНА ДОГОВОРА</div><p style="text-align: justify;">2.1. Цена договора составляет {{contract_price}} рублей.</p><table width="100%" style="margin-top: 30px;"><tr valign="top"><td width="50%" style="text-align: center;"><strong>Застройщик:</strong><br/>{{developer_name}}<br/>Свидетельство: {{developer_certificate}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{developer_signature}}/</td><td width="50%" style="text-align: center;"><strong>Участник:</strong><br/>{{participant_name}}<br/>Паспорт: {{participant_passport}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{participant_signature}}/</td></tr></table>', JSON_OBJECT('contract_number', 'Номер договора', 'city', 'Город заключения', 'contract_date', 'Дата заключения', 'developer_name', 'Наименование застройщика', 'participant_name', 'ФИО участника', 'construction_object', 'Объект долевого строительства', 'contract_price', 'Цена договора', 'developer_certificate', 'Свидетельство застройщика', 'participant_passport', 'Паспорт участника', 'developer_signature', 'Подпись застройщика', 'participant_signature', 'Подпись участника')),

-- СЕМЕЙНЫЕ ДОГОВОРЫ
('Соглашение о порядке общения с ребенком', 'family', 'Соглашение родителей о порядке общения с ребенком', '<div style="text-align: center; font-weight: bold; font-size: 16pt; margin-bottom: 30px;">СОГЛАШЕНИЕ О ПОРЯДКЕ ОБЩЕНИЯ С РЕБЕНКОМ № {{contract_number}}</div><div style="text-align: right; margin-bottom: 20px;">г. {{city}}, {{contract_date}}</div><p style="text-align: justify; line-height: 1.6;">{{parent1_name}}, именуемый(-ая) в дальнейшем "Первый родитель", с одной стороны, и {{parent2_name}}, именуемый(-ая) в дальнейшем "Второй родитель", с другой стороны, заключили настоящее соглашение о нижеследующем:</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">1. ПРЕДМЕТ СОГЛАШЕНИЯ</div><p style="text-align: justify;">1.1. Стороны договариваются о порядке общения Второго родителя с ребенком {{child_name}}, {{child_birth_date}} года рождения.</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">2. ПОРЯДОК ОБЩЕНИЯ</div><p style="text-align: justify;">2.1. Второй родитель имеет право общаться с ребенком: {{communication_schedule}}.</p><table width="100%" style="margin-top: 30px;"><tr valign="top"><td width="50%" style="text-align: center;"><strong>Первый родитель:</strong><br/>{{parent1_name}}<br/>Адрес: {{parent1_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{parent1_signature}}/</td><td width="50%" style="text-align: center;"><strong>Второй родитель:</strong><br/>{{parent2_name}}<br/>Адрес: {{parent2_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{parent2_signature}}/</td></tr></table>', JSON_OBJECT('contract_number', 'Номер договора', 'city', 'Город заключения', 'contract_date', 'Дата заключения', 'parent1_name', 'ФИО первого родителя', 'parent2_name', 'ФИО второго родителя', 'child_name', 'ФИО ребенка', 'child_birth_date', 'Дата рождения ребенка', 'communication_schedule', 'График общения', 'parent1_address', 'Адрес первого родителя', 'parent2_address', 'Адрес второго родителя', 'parent1_signature', 'Подпись первого родителя', 'parent2_signature', 'Подпись второго родителя')); 